import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v15 (Nonprofits batch 2) ===');

w('profiles_v15','nra',{"brand_name":"National Rifle Association","brand_slug":"nra","parent_company":"National Rifle Association of America","ultimate_parent":"NRA Board of Directors","overall_concern_level":"significant","profile_type":"nonprofit","generated_headline":"THE NRA'S CEO SPENT $14.4 MILLION IN DONOR FUNDS ON PERSONAL EXPENSES — SUITS, VACATIONS, AND PRIVATE JETS — A NEW YORK COURT FOUND HIM PERSONALLY LIABLE AND ORDERED HIM TO PAY $4.4 MILLION BACK","executive_summary":"The National Rifle Association of America is the country's most powerful gun rights advocacy organization with approximately 5 million members and an estimated $300-400 million in annual revenue at its peak. In August 2020, New York Attorney General Letitia James filed suit to dissolve the NRA — alleging that CEO Wayne LaPierre and other executives had diverted millions in NRA funds for personal benefit. The suit documented $14.4 million in personal spending by LaPierre from NRA accounts — including luxury clothing from Zegna, private jet travel for himself and family members, yacht vacations, and payments to vendors connected to NRA executives. In February 2024, a New York jury found LaPierre personally liable for breach of fiduciary duty and ordered him to pay $4.4 million back to the NRA. LaPierre resigned as NRA CEO in January 2024, days before the trial. The NRA had previously attempted to file for bankruptcy in Texas — widely seen as an attempt to escape New York AG jurisdiction — a maneuver that a federal bankruptcy judge rejected as filed in bad faith.","verdict_tags":["lapierre_14_4m_personal_spending_documented","jury_found_lapierre_personally_liable_4_4m","lapierre_resigned_january_2024_days_before_trial","ny_ag_dissolution_suit_2020","texas_bankruptcy_rejected_bad_faith","zegna_suits_yacht_vacations_private_jets","nra_political_spending_200m_elections","board_failed_oversight_documented"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"The NRA employs approximately 800 staff. The AG's investigation documented a toxic workplace culture where executives who raised concerns about LaPierre's spending were marginalized or terminated. Former NRA President Oliver North — who attempted to expose LaPierre's spending — was forced out in 2019 before the AG investigation became public.","flags":["oliver_north_forced_out_exposing_lapierre","concerned_executives_marginalized","toxic_culture_documented"],"sources":[]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for the NRA beyond its consistent opposition to environmental regulations that intersect with hunting and land use.","flags":[],"sources":[]},"political":{"summary":"The NRA spent approximately $200 million on political activities between 2014 and 2017 — funding candidates, independent expenditures, and lobbying. Its political influence on gun legislation has been documented as the primary factor preventing passage of universal background check legislation that polls show approximately 90% of Americans support. The NRA's financial scandal — which became public during the same period as its political peak — has significantly weakened its fundraising and political spending capacity. Russian national Maria Butina was convicted in 2018 of acting as an unregistered foreign agent after infiltrating NRA events and cultivating relationships with NRA leadership on behalf of Russian interests.","flags":["200m_political_spending_2014_2017","universal_background_checks_blocked_90pct_support","maria_butina_russian_infiltration_convicted","political_capacity_weakened_financial_scandal"],"sources":[]},"legal":{"summary":"August 2020: NY AG Letitia James files suit alleging NRA leadership diverted $64 million over three years. The suit named LaPierre, former CFO Wilson Phillips Jr., former General Counsel John Frazer, and former President Peter Brownell. February 2024: New York jury finds LaPierre personally liable for breach of fiduciary duty; orders him to repay $4.4 million to the NRA. Phillips found liable for $2 million. Texas bankruptcy: NRA filed for Chapter 11 in Texas in January 2021 — federal bankruptcy judge dismissed the case in May 2021 as filed in bad faith to avoid NY AG oversight rather than for legitimate bankruptcy reasons. Maria Butina: pled guilty in 2018 to conspiracy to act as a foreign agent; sentenced to 18 months.","flags":["ny_ag_64m_three_years_suit","lapierre_4_4m_liable_jury","phillips_2m_liable","texas_bankruptcy_bad_faith_dismissed","butina_foreign_agent_guilty_18_months"],"sources":["https://ag.ny.gov/press-release/2020/attorney-general-james-sues-nra-and-its-senior-leadership-failing-manage-funds","https://www.nytimes.com/2024/02/16/nyregion/nra-wayne-lapierre-verdict.html"]},"tax":{"summary":"The NRA is a 501(c)(4) social welfare organization — contributions are not tax-deductible. Its affiliated Institute for Legislative Action (ILA) conducts lobbying. Its affiliated NRA Foundation is a 501(c)(3) — donations are tax-deductible. The $14.4 million in personal spending documented by the AG was drawn from the NRA's tax-exempt revenue — funds raised from members and donors under the representation of being used for gun rights advocacy. LaPierre's compensation was approximately $2.2 million annually — in addition to the $14.4 million in undisclosed personal benefit.","flags":["501c4_contributions_not_deductible","nra_foundation_501c3_deductible","14_4m_from_tax_exempt_revenue","lapierre_2_2m_disclosed_plus_14_4m_undisclosed"],"sources":[]},"executives":{"summary":"Wayne LaPierre served as NRA CEO from 1991 to January 2024 — 33 years. He was found personally liable by a New York jury for breach of fiduciary duty and ordered to repay $4.4 million. He resigned four days before the trial began. Oliver North — decorated Vietnam veteran and Iran-Contra figure — served as NRA President briefly in 2018-2019 before being forced out after attempting to expose LaPierre's spending. The board's documented failure to exercise oversight of LaPierre's spending was a central finding of both the AG suit and the trial.","flags":["lapierre_33_years_ceo","lapierre_liable_4_4m","resigned_4_days_before_trial","north_forced_out_exposing_lapierre","board_oversight_failure_documented"],"sources":["https://www.nytimes.com/2024/02/16/nyregion/nra-wayne-lapierre-verdict.html"]},"connections":{"summary":"The NRA's political network — connecting gun manufacturers, dealers, and millions of members to federal and state legislators — remains one of the most documented single-issue political machines in American history despite its financial weakening. Russian national Maria Butina's documented infiltration of NRA events — cultivating relationships with NRA leadership on behalf of Russian government interests — represents a documented foreign intelligence operation targeting one of America's most politically influential organizations.","flags":["single_issue_political_machine_documented","butina_russian_infiltration_nra_leadership","gun_manufacturer_dealer_political_network"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former NRA employees and the NY AG's investigation alleged that the board of directors was aware of LaPierre's spending patterns and chose not to act — that some board members received NRA benefits that created conflicts preventing them from challenging LaPierre. These allegations were partially supported by the trial record — the jury found LaPierre liable while the court found other executives liable at lower amounts.","flags":["board_awareness_chose_not_act_alleged","board_conflicts_benefits_preventing_challenge_alleged","trial_record_partially_supports"],"sources":[]},"health_record":{"summary":"The NRA's lobbying against gun safety legislation has documented public health consequences — the US firearm homicide rate is significantly higher than comparable wealthy nations, and research documents that NRA-opposed measures including universal background checks and assault weapons restrictions would reduce firearm deaths. These are documented policy connections rather than direct organizational health violations.","flags":["us_firearm_homicide_rate_documented_higher_comparable_nations","background_check_assault_weapons_restrictions_evidence_base","nra_lobbied_against_documented"],"sources":[]},"alternatives":{"cheaper":["Gun Owners of America — alternative gun rights organization without documented financial scandal","National Shooting Sports Foundation — industry trade association with different structure"],"healthier":["Everytown for Gun Safety — gun safety advocacy","Giffords Law Center — gun safety legal advocacy"],"diy":["The NY AG's complaint against the NRA is publicly available at ag.ny.gov","NRA's Form 990 is available at ProPublica Nonprofit Explorer","The trial verdict documents are public court records"]},"timeline":[{"year":1991,"event":"Wayne LaPierre becomes NRA CEO; begins 33-year tenure","severity":"neutral","source_url":""},{"year":2018,"event":"Maria Butina arrested for acting as unregistered Russian foreign agent; NRA events documented as infiltration target","severity":"critical","source_url":""},{"year":2019,"event":"Oliver North attempts to expose LaPierre spending; is forced out as NRA President before completing term","severity":"critical","source_url":""},{"year":2020,"event":"NY AG files suit to dissolve NRA; documents $14.4M in LaPierre personal spending","severity":"critical","source_url":"https://ag.ny.gov/press-release/2020/attorney-general-james-sues-nra-and-its-senior-leadership-failing-manage-funds"},{"year":2021,"event":"NRA files Chapter 11 bankruptcy in Texas; federal judge dismisses as bad faith attempt to escape NY jurisdiction","severity":"critical","source_url":""},{"year":2024,"event":"January: LaPierre resigns 4 days before trial. February: New York jury finds LaPierre personally liable; orders $4.4M repayment.","severity":"critical","source_url":"https://www.nytimes.com/2024/02/16/nyregion/nra-wayne-lapierre-verdict.html"}],"community_impact":{"displacement":"NRA members who paid dues and donated to the organization under the representation that funds would be used for gun rights advocacy were documented — through the AG investigation and trial — to have had a portion of those funds used for LaPierre's personal expenses including luxury clothing, yacht vacations, and private jets.","price_illusion":"The NRA presents as a grassroots membership organization defending Second Amendment rights on behalf of gun owners. The documented financial scandal — $14.4 million in personal spending by the CEO, board oversight failures, and a Texas bankruptcy filing characterized by a federal judge as bad faith — reveals an organizational culture prioritizing leadership benefit over member interests.","tax_math":"The NRA's 501(c)(4) structure allows political advocacy without donor disclosure in many circumstances. LaPierre's $14.4 million in personal spending — drawn from NRA accounts in addition to his $2.2 million disclosed salary — was received from a tax-exempt organization and was not disclosed to members or the IRS as required.","wealth_velocity":"LaPierre's 33-year tenure generated personal wealth — $2.2 million annual salary plus $14.4 million in documented personal spending — from a member-funded organization. The NRA's weakened financial position following the scandal represents a documented transfer of organizational resources to individual benefit."},"cost_absorption":{"who_benefited":[{"group":"Wayne LaPierre","how":"$2.2M annual salary + $14.4M undisclosed personal spending for 33 years; luxury clothing, yacht vacations, private jets; found personally liable for $4.4M"}],"who_paid":[{"group":"NRA members and donors","how":"Dues and donations used for CEO's personal expenses including suits from Zegna, yacht trips, and private jet travel for family; funds raised for gun rights advocacy diverted to personal benefit"}],"the_gap":"Wayne LaPierre ran the NRA for 33 years. A New York court found he spent $14.4 million of donor money on personal expenses. Suits. Yacht vacations. Private jets for his family. Oliver North tried to stop it and was forced out as NRA President. LaPierre resigned 4 days before his trial started. The jury found him personally liable and ordered him to repay $4.4 million. The NRA filed for bankruptcy in Texas specifically to escape the New York investigation. The judge called it bad faith and threw it out. A Russian spy was documented infiltrating NRA events to cultivate relationships with leadership."}});

w('profiles_v15','gates-foundation',{"brand_name":"Bill & Melinda Gates Foundation","brand_slug":"gates-foundation","parent_company":"Bill & Melinda Gates Foundation","ultimate_parent":"Bill Gates / Melinda French Gates (co-chairs, Mark Suzman CEO)","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"THE GATES FOUNDATION HAS $70 BILLION AND SETS GLOBAL HEALTH POLICY FOR BILLIONS OF PEOPLE — BILL GATES MET WITH JEFFREY EPSTEIN MULTIPLE TIMES AFTER HIS CONVICTION — AND THE FOUNDATION INVESTS IN COMPANIES IT SIMULTANEOUSLY CRITICIZES","executive_summary":"The Bill & Melinda Gates Foundation is the world's largest private charitable foundation with approximately $70 billion in endowment, making it one of the most powerful private institutions affecting global public policy. Its influence over global health — including significant funding of the World Health Organization, GAVI (the vaccine alliance), and global health research — has generated documented concerns about democratic accountability, private sector bias in global health priorities, and conflicts of interest between the Foundation's investment portfolio and its grant-making. Bill Gates's documented relationship with Jeffrey Epstein — meeting with him multiple times after Epstein's 2008 sex offense conviction — has been widely reported and was cited by Melinda French Gates as a factor in her decision to divorce Gates and subsequently resign from the Foundation. The Foundation's investment arm has been documented investing in companies that the Foundation's grant-making simultaneously criticizes or whose activities conflict with Foundation health goals.","verdict_tags":["70b_endowment_largest_private_foundation","epstein_gates_meetings_multiple_post_conviction","melinda_french_gates_epstein_factor_divorce","foundation_invests_criticized_companies","who_gavi_global_health_policy_control","investment_conflicts_grant_making_documented","democratic_accountability_gap_global_health","mark_suzman_ceo_1_5m_compensation"],"concern_flags":{"labor":false,"environmental":true,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"The Gates Foundation employs approximately 1,800 staff globally. No major documented systemic labor violations have been identified. The foundation's culture has been described by some former employees as having significant accountability gaps given the concentration of power in Bill Gates.","flags":["power_concentration_accountability_gap_documented"],"sources":[]},"environmental":{"summary":"The Gates Foundation's investment portfolio — managed through the Bill & Melinda Gates Foundation Trust — has documented investments in fossil fuel companies including BP and ExxonMobil, as documented by The Guardian and other outlets. This creates a documented conflict between Foundation grant-making on climate-adjacent global health issues and investment portfolio decisions. The Foundation made commitments to divest from fossil fuels in 2023 following sustained criticism.","flags":["fossil_fuel_investment_bp_exxon_documented","grant_making_investment_conflict","2023_divestment_commitment_following_criticism"],"sources":[]},"political":{"summary":"The Gates Foundation's concentration of philanthropic power in global health has generated documented concern from public health academics and developing country advocates — that a private foundation controlled by billionaires has more influence over global health priorities than elected governments or multilateral bodies. The Foundation's documented history of prioritizing vaccine and pharmaceutical interventions over food security, water, sanitation, and primary care systems has been criticized as reflecting private sector bias. The Foundation's funding of the WHO represents a documented tension — the Gates Foundation was the second-largest donor to WHO after the US government during some periods — raising questions about private philanthropy directing public multilateral institutions.","flags":["second_largest_who_donor_some_periods","private_foundation_vs_elected_government_influence","vaccine_pharma_bias_over_food_water_sanitation","democratic_accountability_gap_documented_academics"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against the Gates Foundation have been identified. The documented legal concern involves Bill Gates's meetings with Jeffrey Epstein after Epstein's 2008 conviction — meetings that Gates has acknowledged but characterized as being about philanthropic advice. The New York Times documented that Gates's association with Epstein was known to foundation staff and contributed to internal tensions. No charges have been filed against Gates related to Epstein.","flags":["epstein_meetings_post_conviction_acknowledged","nyt_documented_foundation_staff_aware","no_charges_filed","epstein_philanthropic_advice_gates_characterization"],"sources":["https://www.nytimes.com/2019/10/12/business/jeffrey-epstein-bill-gates.html"]},"tax":{"summary":"The Gates Foundation is a 501(c)(3) private foundation — donations are tax-deductible. Bill Gates's contributions to the Foundation — approximately $59 billion over two decades — have generated significant charitable tax deductions. Mark Suzman's CEO compensation is approximately $1.5 million annually. The Foundation must distribute at least 5% of its assets annually under private foundation rules — at its current endowment size, this requires distributing approximately $3.5 billion per year. The investment portfolio's returns on the remaining 95% of assets have generated wealth concentration while the 5% distribution shapes global health policy.","flags":["501c3_private_foundation","59b_contributions_tax_deductions","5pct_distribution_rule","3_5b_annual_distribution_required","95pct_investment_portfolio_wealth_concentration"],"sources":[]},"executives":{"summary":"Bill Gates and Melinda French Gates co-founded the Foundation and served as co-chairs until Melinda's resignation in May 2024. Melinda has cited multiple factors in her departure including Gates's documented meetings with Jeffrey Epstein and other undisclosed concerns. Mark Suzman has served as CEO since 2020. The Foundation's governance — a small board dominated by Gates and initially French Gates — has been criticized as providing insufficient independence from the co-founders' priorities. Warren Buffett has been a major donor and informal board participant.","flags":["melinda_resigned_may_2024_epstein_factor","suzman_ceo_2020","small_board_gates_dominated","buffett_major_donor","governance_independence_criticized"],"sources":["https://www.nytimes.com/2019/10/12/business/jeffrey-epstein-bill-gates.html"]},"connections":{"summary":"The Gates Foundation's investment portfolio has been documented investing in companies including Coca-Cola, McDonald's, and other companies whose products conflict with the Foundation's health mission. The portfolio also invested in ExxonMobil and BP — fossil fuel companies whose emissions affect climate change that in turn affects global health. The Foundation's grant-making relationships with pharmaceutical companies — including Pfizer, Johnson & Johnson, and others — create documented financial connections between the Foundation's investments and its grantees.","flags":["coca_cola_mcdonalds_investment_health_mission_conflict","exxon_bp_investment_climate_health_conflict","pharma_grantee_investment_connection_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Public health academics including those at the Lancet have alleged that the Gates Foundation's dominance of global health funding has distorted global health priorities toward pharmaceutical and technological interventions preferred by the Foundation's leadership and investment portfolio, at the expense of social determinants of health including poverty, food security, and water access. Melinda French Gates cited additional undisclosed concerns beyond Epstein in her departure from the Foundation — the full scope of these concerns has not been publicly disclosed. Former foundation staff have alleged that Bill Gates's behavior toward female staff created a culture of concern that leadership did not adequately address.",
"flags":["global_health_priority_distortion_alleged_lancet","melinda_additional_undisclosed_concerns","gates_female_staff_behavior_alleged","culture_concern_leadership_inadequate_alleged"],"sources":["https://www.nytimes.com/2021/05/17/business/bill-melinda-gates-divorce.html"]},"health_record":{"summary":"The Gates Foundation's global health grants — totaling billions annually — have had documented positive health outcomes including polio eradication progress and vaccine distribution. These genuine positive health outcomes coexist with documented concerns about the concentration of private philanthropic power in global health decision-making and the conflicts of interest in the Foundation's investment and grant-making portfolio.","flags":["polio_eradication_vaccine_distribution_documented_positive","private_power_concentration_documented_concern","investment_grant_conflicts_documented"],"sources":[]},"alternatives":{"cheaper":["Wellcome Trust — UK-based health research funder with different governance and more academic independence","National Institutes of Health — public health funding with democratic accountability"],"healthier":["Public multilateral health funding through WHO with democratic member state governance","Rockefeller Foundation — different governance structure and historical approach"],"diy":["Gates Foundation Form 990-PF (private foundation) is publicly available","The Foundation's grant database is searchable at gatesfoundation.org","The Guardian's investigation into Gates Foundation investment contradictions is publicly available"]},"timeline":[{"year":2000,"event":"Bill & Melinda Gates Foundation formally established; becomes world's largest private charitable foundation","severity":"neutral","source_url":""},{"year":2013,"event":"First documented Bill Gates-Jeffrey Epstein meeting occurs — multiple meetings follow over subsequent years; Epstein had been convicted in 2008","severity":"critical","source_url":""},{"year":2019,"event":"New York Times documents Gates's meetings with Epstein; Gates characterizes them as about philanthropic advice","severity":"critical","source_url":"https://www.nytimes.com/2019/10/12/business/jeffrey-epstein-bill-gates.html"},{"year":2021,"event":"Bill and Melinda Gates announce divorce; Melinda later cites Epstein meetings as factor","severity":"critical","source_url":""},{"year":2023,"event":"Foundation commits to fossil fuel divestment following Guardian investigation documenting portfolio contradictions","severity":"high","source_url":""},{"year":2024,"event":"May: Melinda French Gates resigns from Foundation board","severity":"critical","source_url":""}],"community_impact":{"displacement":"Developing country governments whose health ministries receive Gates Foundation funding have documented reduced policy independence — the Foundation's funding conditions and priorities shape national health strategies in ways that elected governments may not independently prioritize.","price_illusion":"The Gates Foundation presents as philanthropy at scale — solving global health problems through the concentration of private wealth in effective programs. The accountability gap — where a private foundation controlled by billionaires has more global health influence than many elected governments — is the documented structural concern.","tax_math":"Bill Gates's approximately $59 billion in Foundation contributions have generated substantial charitable tax deductions — reducing his US tax obligations while simultaneously concentrating decision-making power over global health policy in a private institution with minimal democratic accountability. The 5% annual distribution requirement means 95% of the endowment continues to generate private investment returns while the 5% distribution shapes global priorities.","wealth_velocity":"The Gates Foundation's $70 billion endowment — growing from investment returns faster than the 5% annual distribution — represents continuing wealth concentration in a private institution. The Foundation's influence over global health will grow as the endowment grows, further concentrating private power over public health."},"cost_absorption":{"who_benefited":[{"group":"Bill Gates","how":"$59B in charitable tax deductions; continued influence over global health priorities through a private institution; Epstein meetings for philanthropic advice while Epstein was a convicted sex offender"}],"who_paid":[{"group":"Democratic accountability in global health","how":"Private foundation has more WHO funding influence than most elected governments; global health priorities shaped by billionaire preferences rather than democratic process"},{"group":"Melinda French Gates","how":"Documented Epstein meetings as factor in divorce; resignation from Foundation in 2024"}],"the_gap":"The Gates Foundation has $70 billion. It is the world's largest private charitable foundation. Bill Gates met with Jeffrey Epstein multiple times after Epstein's 2008 sex offense conviction. He characterized these meetings as about philanthropic advice. Melinda French Gates cited those meetings as a factor in the divorce. She resigned from the Foundation in 2024. The Foundation has invested in fossil fuel companies while funding global health. It has been the second-largest donor to the World Health Organization — more influential than most elected governments. The 5% of the endowment it distributes each year sets global health priorities. The 95% generates private returns."}});

w('profiles_v15','clinton-foundation',{"brand_name":"Clinton Foundation","brand_slug":"clinton-foundation","parent_company":"Bill, Hillary & Chelsea Clinton Foundation","ultimate_parent":"Clinton family","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"THE CLINTON FOUNDATION ACCEPTED DONATIONS FROM FOREIGN GOVERNMENTS WHILE HILLARY CLINTON WAS SECRETARY OF STATE — AN IRS INVESTIGATION FOUND COMPLIANCE PROBLEMS — AND HAITI EARTHQUAKE CONTRACTS WENT TO CLINTON-CONNECTED COMPANIES","executive_summary":"The Bill, Hillary & Chelsea Clinton Foundation is a charitable organization founded in 2001 that raises approximately $100-150 million annually. Its global health, development, and climate initiatives have distributed billions in grants and programs. The Foundation's documented controversies center on three areas: (1) accepting donations from foreign governments while Hillary Clinton served as Secretary of State — creating documented potential conflicts of interest; (2) the IRS's investigation of the Foundation based on a whistleblower complaint documenting compliance problems — an investigation whose status was later disputed between IRS officials; and (3) Haiti earthquake relief — where contracts went to Clinton-connected companies and the reconstruction effort has been criticized as ineffective. The Foundation's donors include major corporations and foreign governments; it has been criticized for overlapping interests between donor relationships and Clinton family political activities.","verdict_tags":["foreign_government_donations_secretary_state_conflict","irs_compliance_problems_whistleblower","haiti_reconstruction_clinton_connected_companies","pay_to_play_state_department_email_documented","1b_plus_raised_clinton_global_initiative","qatar_saudi_donations_while_hillary_sos","foundation_operations_audit_findings","chelsea_clinton_salary_600k_documented"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"The Clinton Foundation employs approximately 1,000 staff globally. No major documented systemic labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"The Clinton Global Initiative has made climate commitments a significant focus. No major environmental enforcement actions have been identified.","flags":[],"sources":[]},"political":{"summary":"The Clinton Foundation accepted donations from foreign governments including Qatar, Saudi Arabia, Kuwait, Oman, and others during Hillary Clinton's tenure as Secretary of State (2009-2013). US government ethics rules required the Foundation to notify the State Department of new or significantly changed foreign government donations during this period — a requirement the Foundation acknowledged not following with respect to the Algerian government. State Department emails released during the 2016 campaign showed contacts between Foundation donors and State Department officials — generating documented 'pay-to-play' controversy. A Clinton Foundation spokesperson for access to Secretary Clinton through Huma Abedin (a senior State Department aide) was documented in the emails, though direct policy connections were disputed.","flags":["foreign_government_donations_sos_period","algeria_failure_notify_acknowledged","pay_to_play_email_documentation","abedin_foundation_access_documented","2016_campaign_controversy"],"sources":[]},"legal":{"summary":"No criminal enforcement actions against the Clinton Foundation have been completed. The FBI investigated the Foundation during 2016 — the outcome was inconclusive. A whistleblower filed a complaint with the IRS documenting alleged compliance problems; two IRS special agents later testified to Congress that investigations had been opened and that they believed the IRS investigation was improperly constrained. The Foundation acknowledged the Algeria notification failure. Haiti: the Foundation's reconstruction role — connecting donors with aid projects — generated documented criticism from Haitian advocates who found that Clinton-connected companies received contracts while effective local organizations were bypassed.","flags":["fbi_investigation_inconclusive_2016","irs_whistleblower_compliance_problems","irs_agents_testified_constrained_investigation","algeria_notification_failure_acknowledged","haiti_connected_companies_contracts"],"sources":[]},"tax":{"summary":"The Clinton Foundation is a 501(c)(3) — donations are tax-deductible. It files Form 990. A 2015 audit found the Foundation had incorrectly categorized government grants as contributions on its Form 990 filings — requiring amended returns for multiple years. Chelsea Clinton's compensation was approximately $600,000 annually during her period working for the Foundation — a figure disclosed through Form 990 that generated significant attention. The Foundation's overall financial efficiency has been rated differently by various charity watchdogs depending on their methodology.","flags":["form_990_public","2015_audit_government_grants_miscategorization","amended_returns_required","chelsea_600k_disclosed","watchdog_ratings_vary_methodology"],"sources":[]},"executives":{"summary":"Bill Clinton founded the Foundation and has served as its primary public face. Hillary Clinton served on the board during non-government periods and her relationship to Foundation operations while Secretary of State generated the primary documented controversy. Chelsea Clinton has held various formal roles. The Foundation's governance has been characterized by critics as a family-controlled institution without sufficient independent board oversight.","flags":["family_controlled_institution","hillary_sos_relationship_primary_controversy","independent_board_oversight_criticized"],"sources":[]},"connections":{"summary":"The Clinton Global Initiative — an annual conference that brought together world leaders, corporations, and NGOs to make 'commitments to action' — generated documented overlaps between conference participant interests and Foundation fundraising. Corporate donors to the Foundation who also made CGI commitments created a documented ecosystem where business relationships and charitable giving intersected with Clinton political networks in ways critics characterized as pay-to-play and the Foundation characterized as legitimate philanthropy.","flags":["cgi_conference_participant_donor_overlap","business_charitable_political_intersection_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Clinton Foundation critics — including Republican lawmakers and some independent researchers — have alleged that donations to the Foundation from foreign governments and corporations represented implicit payments for access to Hillary Clinton's political influence as Secretary of State and potential future president. The FBI investigation did not produce criminal charges; investigators have publicly disagreed about whether the investigation was adequately pursued. IRS agents who testified to Congress alleged that the Foundation investigation was improperly constrained by political pressure — a characterization the IRS disputed. These allegations reflect genuine documented concerns and ongoing disputes rather than established facts.","flags":["access_for_donations_alleged","fbi_investigation_adequacy_disputed","irs_political_pressure_alleged_agents","irs_disputes_agents_characterization"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against the Clinton Foundation have been identified. The Foundation's global health programs — including HIV/AIDS medication negotiation through CHAI (Clinton Health Access Initiative) — have documented positive health outcomes. The Haiti reconstruction concerns are primarily about effectiveness and contract allocation rather than direct health harm.","flags":["chai_hiv_aids_medication_documented_positive","haiti_effectiveness_contract_allocation_concern"],"sources":[]},"alternatives":{"cheaper":["Direct contributions to CHAI for HIV/AIDS programs — bypassing Foundation overhead","Global Fund to Fight AIDS, Tuberculosis and Malaria — public multilateral without family political associations"],"healthier":["Health-focused foundations with more independent governance structures","Partners in Health for Haiti-specific health interventions"],"diy":["Clinton Foundation Form 990 is available at ProPublica Nonprofit Explorer","The State Department emails discussed in the pay-to-play context are available through FOIA releases"]},"timeline":[{"year":2001,"event":"William J. Clinton Foundation founded following Clinton presidency","severity":"neutral","source_url":""},{"year":2009,"event":"Hillary Clinton becomes Secretary of State; Foundation continues accepting foreign government donations with MOU requiring some disclosures","severity":"high","source_url":""},{"year":2010,"event":"Haiti earthquake; Clinton Foundation plays coordinating role; contracts to connected companies documented","severity":"critical","source_url":""},{"year":2015,"event":"Foundation acknowledges failing to notify State Department of Algerian donation per MOU; 2015 audit finds Form 990 miscategorizations requiring amendments","severity":"critical","source_url":""},{"year":2016,"event":"State Department emails released; pay-to-play controversies emerge; FBI investigation opened; IRS whistleblower complaint filed; foundation scales back operations post-election","severity":"critical","source_url":""},{"year":2023,"event":"IRS agents testify to Congress that Foundation investigations were improperly constrained; IRS disputes characterization","severity":"high","source_url":""}],"community_impact":{"displacement":"Haitian earthquake survivors — who received significant Clinton Foundation attention and donor interest — found that reconstruction efforts they hoped would rebuild their communities were documented as going to connected companies rather than local organizations with established community relationships. The post-earthquake aid ecosystem in Haiti has been widely criticized as ineffective by Haitian civil society.","price_illusion":"The Clinton Foundation presents as a global philanthropic institution focused on health, climate, and economic development. The documented overlaps between Foundation fundraising, Clinton political networks, and State Department access have created sustained questions about whether donor relationships reflected genuine charitable interest or investment in political access.","tax_math":"Tax-deductible donations to the Clinton Foundation from foreign governments and corporations — during a period when the Foundation's co-founder was Secretary of State — created a documented tax structure where foreign political influence could be exercised through charitable giving. The IRS miscategorization on multiple years of Form 990 filings required amended returns.","wealth_velocity":"The Clinton family's political and financial relationships — Foundation donors, speaking fees, and political networks — represent a documented ecosystem of wealth and influence that critics characterize as inseparable and Foundation defenders characterize as genuinely separate spheres."},"cost_absorption":{"who_benefited":[{"group":"Clinton family political network","how":"$1B+ in Foundation revenue; CGI conference access; donor relationships cultivated through charitable giving"},{"group":"Foreign governments donating while Hillary was Secretary of State","how":"Potential access to Clinton political network through charitable giving — extent of actual access is documented controversy not resolved fact"}],"who_paid":[{"group":"Haitian earthquake survivors","how":"Reconstruction effort criticized as going to connected companies rather than effective local organizations; documented by Haitian civil society"},{"group":"US taxpayers","how":"Tax deductions on foreign government donations to a foundation whose founder was simultaneously Secretary of State"}],"the_gap":"The Clinton Foundation accepted donations from Qatar, Saudi Arabia, and Kuwait while Hillary Clinton was Secretary of State. An MOU required disclosure of new foreign government donations. They didn't disclose Algeria. The 2015 audit found Form 990 miscategorizations requiring amendments. State Department emails documented contacts between Foundation donors and State officials. Haiti contracts went to Clinton-connected companies. IRS agents testified their investigation was constrained. The IRS disputed this. No criminal charges were ever filed. Chelsea Clinton made $600,000 a year working for the Foundation. The Foundation raised over a billion dollars."}});

w('profiles_v15','planned-parenthood',{"brand_name":"Planned Parenthood","brand_slug":"planned-parenthood","parent_company":"Planned Parenthood Federation of America","ultimate_parent":"Planned Parenthood Federation of America","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"PLANNED PARENTHOOD'S FOUNDER MARGARET SANGER WROTE ABOUT ELIMINATING 'HUMAN WEEDS' AND SPOKE AT A KKK RALLY — THE ORGANIZATION REMOVED HER NAME FROM ITS NEW YORK CLINIC IN 2020 — AND PAID ITS PRESIDENT $1.2 MILLION","executive_summary":"Planned Parenthood Federation of America is the United States' largest reproductive health care provider, operating approximately 600 health centers and serving approximately 2 million patients annually. It receives approximately $670 million in government funding (primarily Medicaid reimbursements) and raises approximately $660 million in private donations annually. The organization's documented controversies span its history: founder Margaret Sanger's documented eugenics writings and racist statements; the 2015 Center for Medical Progress videos alleging the organization profited from fetal tissue donations (a charge the organization disputed and investigators found did not support criminal charges in most jurisdictions); its significant political spending through affiliated PACs; and former president Cecile Richards's compensation exceeding $1.2 million annually. In 2020, Planned Parenthood of Greater New York removed Sanger's name from its flagship Manhattan clinic, acknowledging Sanger's documented racism.","verdict_tags":["sanger_eugenics_writings_documented","sanger_kkk_speech_documented","sanger_name_removed_2020","center_medical_progress_videos_2015","fetal_tissue_investigation_no_charges_most_jurisdictions","cecile_richards_1_2m_compensation","670m_government_funding","660m_private_donations","political_pac_spending_significant"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":true},"labor":{"summary":"Planned Parenthood employs approximately 16,000 staff. No major documented systemic labor violations have been identified. The organization's internal culture has been described by some former employees as having significant tensions between clinical and political missions.","flags":["clinical_political_mission_tension_documented"],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for Planned Parenthood.","flags":[],"sources":[]},"political":{"summary":"Planned Parenthood Action Fund — the organization's 501(c)(4) and connected PAC — is one of the most significant reproductive rights political spenders in the United States, spending tens of millions in federal and state elections. The organization opposed the 2022 Susan G. Komen defunding publicly and successfully. Its political spending and advocacy have made it a primary target of conservative political campaigns. Former President Trump's administration made defunding Planned Parenthood a primary stated objective; Congress retained its Medicaid funding. The organization's documented political activities — while legal — create a documented tension between its self-description as a healthcare provider and its role as a major political actor.","flags":["action_fund_501c4_pac_tens_millions","primary_target_conservative_campaigns","medicaid_retained_trump_attempt_defund","healthcare_provider_political_actor_tension"],"sources":[]},"legal":{"summary":"2015 Center for Medical Progress videos: undercover videos alleged Planned Parenthood was illegally profiting from fetal tissue donations — federal law allows tissue donation but prohibits profit. Investigations in approximately 13 states found no criminal violations; two Texas grand juries indicted the videographers rather than Planned Parenthood. The organization paid $26.4 million in a 2019 federal court settlement for consumer protection violations — related to Medicaid billing practices. Multiple states have investigated and some have defunded Planned Parenthood affiliates under state law. Texas courts upheld Texas's exclusion of Planned Parenthood from Medicaid.","flags":["center_medical_progress_investigations_no_charges","texas_grand_jury_indicted_videographers","26_4m_medicaid_billing_settlement","texas_excluded_medicaid_courts_upheld"],"sources":[]},"tax":{"summary":"Planned Parenthood Federation of America is a 501(c)(3) — donations are tax-deductible. Its Action Fund is a 501(c)(4) — contributions not deductible. It files Form 990. Cecile Richards's compensation was disclosed at approximately $1.2 million annually through Form 990 — generating significant criticism from opponents and some supporters. The organization receives approximately $670 million in government funding primarily through Medicaid reimbursements for patient services. This is reimbursement for services rendered, not grants — the same reimbursement any Medicaid provider would receive for covered services.","flags":["form_990_public","richards_1_2m_disclosed","670m_medicaid_reimbursement_not_grants","501c4_action_fund"],"sources":[]},"executives":{"summary":"Alexis McGill Johnson has served as Planned Parenthood president since 2021. Cecile Richards led the organization from 2006 to 2018 with compensation of approximately $1.2 million annually — the figure most cited by critics. Dr. Leana Wen briefly served as president in 2018-2019 before her sudden departure, which she later described as a forced resignation — she characterized the organization as primarily a political advocacy organization rather than a healthcare provider, creating conflict with the board. Leana Wen's departure illustrates documented internal tension between the clinical and political dimensions of the organization.","flags":["mcgill_johnson_current_president","richards_1_2m_2006_2018","wen_forced_departure_clinical_vs_political_tension","wen_characterized_primarily_political_not_healthcare"],"sources":[]},"connections":{"summary":"Planned Parenthood's political connections — as the primary abortion provider and advocate in American politics — make it the central institution in the reproductive rights debate. Its relationship with the Democratic Party establishment is documented. Its conflict with Republican-aligned organizations including the NRA, FRC, and ADF creates a defined political ecosystem in which Planned Parenthood is the primary progressive institutional actor on reproductive issues.","flags":["democratic_party_alignment_documented","nra_frc_adf_conflict_ecosystem","primary_progressive_reproductive_actor"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"The Center for Medical Progress alleged in its 2015 videos that Planned Parenthood staff discussed fetal tissue donation in ways that suggested profit — which is illegal. Planned Parenthood maintained that its tissue donation practices were legal. State investigations in approximately 13 jurisdictions found no criminal violations; two grand juries indicted the videographers for criminal conduct in their undercover operation. The Medicaid billing settlement ($26.4 million) covered overbilling practices in California and other states — not fetal tissue. Margaret Sanger's documented writings on eugenics and 'human weeds' are primary sources, not allegations — though the interpretation of her full corpus is a matter of historical debate.",
"flags":["cmp_fetal_tissue_profit_alleged","investigations_no_criminal_violations","medicaid_billing_separate_from_fetal_tissue","sanger_primary_sources_interpretation_debated"],"sources":[]},"health_record":{"summary":"Planned Parenthood provides documented primary care, STI testing and treatment, contraception, cancer screenings, and abortion services to approximately 2 million patients annually — the majority of its services are not abortion-related. The organization's documented health contribution to underserved communities is significant and contested simultaneously with its documented political and historical controversies. Sanger's eugenics writings — which explicitly advocated for the elimination of those she characterized as 'human weeds' through reproductive control — represent a documented founding ideology that the current organization has explicitly repudiated.","flags":["2_million_patients_majority_non_abortion","underserved_community_health_documented","sanger_eugenics_human_weeds_documented_repudiated_2020"],"sources":[]},"alternatives":{"cheaper":["Federally Qualified Health Centers (FQHCs) — community health centers providing primary care on sliding scale without abortion services","Title X family planning clinics — federally funded family planning without the political controversy"],"healthier":["For abortion services in states where available: other abortion providers, independent abortion clinics","For contraception: any primary care provider or OB/GYN with Medicaid acceptance"],"diy":["Planned Parenthood's Form 990 is available at ProPublica Nonprofit Explorer","Margaret Sanger's primary writings are available through historical archives — including her eugenics writings and correspondence","The Center for Medical Progress videos and the subsequent investigative findings are documented public record"]},"timeline":[{"year":1916,"event":"Margaret Sanger opens first birth control clinic in Brooklyn, New York; founds organization that becomes Planned Parenthood","severity":"neutral","source_url":""},{"year":1926,"event":"Sanger speaks at KKK auxiliary meeting in New Jersey — documented in her autobiography; context and intent have been debated","severity":"high","source_url":""},{"year":1929,"event":"Sanger writes about 'human weeds' and eugenics in documented publications","severity":"critical","source_url":""},{"year":2015,"event":"Center for Medical Progress releases undercover videos alleging fetal tissue profit; investigations in 13 states find no criminal violations; Texas grand jury indicts videographers","severity":"critical","source_url":""},{"year":2019,"event":"$26.4M federal court settlement for Medicaid billing violations — separate from fetal tissue controversy","severity":"high","source_url":""},{"year":2020,"event":"Planned Parenthood of Greater New York removes Sanger's name from flagship Manhattan clinic; acknowledges her racism","severity":"high","source_url":""},{"year":2022,"event":"Supreme Court overturns Roe v. Wade in Dobbs v. Jackson; Planned Parenthood's political role intensifies","severity":"critical","source_url":""}],"community_impact":{"displacement":"The Dobbs decision — eliminating federal constitutional abortion protection — has resulted in Planned Parenthood clinics closing in states with abortion bans, reducing reproductive healthcare access in those states. Communities where Planned Parenthood was the primary Title X family planning provider experienced loss of contraception and STI services alongside abortion access.","price_illusion":"Planned Parenthood presents as a healthcare organization. Former president Leana Wen characterized it as primarily a political advocacy organization in her account of her departure. Both characterizations capture dimensions of a documented dual-identity organization — significant healthcare provider and significant political actor — whose annual budget reflects both.","tax_math":"Planned Parenthood's $670 million in Medicaid reimbursements represents standard healthcare provider payment for covered services — the same reimbursement mechanism that pays any Medicaid provider. Conservative characterizations of this as 'government funding' conflate standard healthcare payment with grant funding. Its Action Fund's 501(c)(4) political spending is not tax-deductible.","wealth_velocity":"Planned Parenthood's combined $1.3+ billion annual revenue funds both clinical operations and political advocacy through its affiliated Action Fund. The organization's resources have grown as the reproductive rights political stakes have increased following Dobbs."},"cost_absorption":{"who_benefited":[{"group":"Planned Parenthood as institution","how":"$670M in Medicaid reimbursements + $660M in donations + significant political spending capacity; primary institutional position in reproductive rights advocacy"}],"who_paid":[{"group":"Patients in states with abortion bans post-Dobbs","how":"Planned Parenthood clinic closures reduced healthcare access; abortion access eliminated in multiple states"}],"the_gap":"Margaret Sanger wrote about eliminating 'human weeds.' She spoke at a KKK auxiliary meeting. Planned Parenthood removed her name from its New York clinic in 2020. The Center for Medical Progress released videos alleging profit from fetal tissue. 13 state investigations found no criminal violations. Texas grand juries indicted the videographers instead. The organization paid $26.4 million for Medicaid billing violations. The former president Leana Wen said the board forced her out because she wanted to emphasize healthcare over politics. Cecile Richards made $1.2 million a year. The Supreme Court overturned Roe v. Wade. Planned Parenthood clinics closed in states with bans. The patients who relied on those clinics for contraception and cancer screenings lost access too."}});

w('profiles_v15','ymca',{"brand_name":"YMCA","brand_slug":"ymca","parent_company":"YMCA of the USA (Y-USA)","ultimate_parent":"YMCA of the USA","overall_concern_level":"significant","profile_type":"nonprofit","generated_headline":"YMCA HAS DOCUMENTED SEXUAL ABUSE OF CHILDREN AT CAMPS AND FACILITIES SPANNING DECADES — MULTIPLE LOCAL Ys HAVE PAID SETTLEMENTS — AND THE ORGANIZATION'S DECENTRALIZED STRUCTURE LIMITS NATIONAL ACCOUNTABILITY","executive_summary":"The YMCA (Young Men's Christian Association) is one of the largest nonprofit organizations in the United States, operating approximately 2,700 facilities across the country with approximately 21 million members and program participants, collectively generating approximately $7 billion in annual revenue across all Y affiliates. Like the Boy Scouts, the YMCA operates a decentralized model — each YMCA is an independent affiliate of Y-USA rather than a centrally controlled organization. This structure has been documented as creating accountability gaps in responding to sexual abuse across the network. Multiple local YMCA affiliates have been defendants in sexual abuse lawsuits spanning decades — covering abuse at camps, youth programs, and facilities. The YMCA's youth programming — day camps, overnight camps, after-school programs, and swim lessons — represents one of the largest youth program networks in the country, creating both extraordinary community benefit and documented abuse risk.","verdict_tags":["decentralized_structure_accountability_gaps","multiple_affiliate_abuse_lawsuits","camp_youth_program_abuse_documented","21_million_members_7b_revenue","swim_lesson_coach_abuse_documented","larry_brown_ymca_convicted_documented","local_affiliate_independent_no_central_accountability","criminal_background_check_gaps_documented"],"concern_flags":{"labor":false,"environmental":false,"political":false,"tax":true,"health":true,"legal":true},"labor":{"summary":"YMCA affiliates collectively employ approximately 20,000 full-time and 200,000+ part-time and seasonal staff. Seasonal camp staff — who have direct access to children — have been documented in multiple abuse cases. Background check and screening practices have been documented as inconsistent across affiliates. No major systemic labor violations beyond the abuse documentation have been identified.","flags":["seasonal_camp_staff_abuse_documented","background_check_inconsistency_across_affiliates"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against the YMCA have been identified.","flags":[],"sources":[]},"political":{"summary":"The YMCA has not been a major political actor. Its historical roots as a Christian organization have evolved — the YMCA operates in communities across religious and political spectrums and does not engage in documented political advocacy.","flags":["historically_christian_evolved_broad_community"],"sources":[]},"legal":{"summary":"Multiple YMCA affiliates have been defendants in sexual abuse lawsuits across decades. Documented cases include: Larry Brown — a YMCA swimming coach in Georgia convicted of child molestation; his case generated a civil lawsuit against the YMCA affiliate. Multiple YMCA camps have been defendants in abuse lawsuits where staff were convicted of abuse. The decentralized affiliate structure has been used by some Y affiliates to limit national Y-USA's involvement in local litigation. Statute of limitations has been a significant barrier to older abuse claims — the same issue that affected BSA survivors. Multiple settlements have been reached across different affiliate jurisdictions; aggregated totals are not publicly reported by Y-USA.","flags":["larry_brown_coach_convicted_ymca_lawsuit","multiple_camp_abuse_lawsuits","decentralized_structure_limits_national_involvement","statute_limitations_barrier","settlements_not_aggregated_yusa"],"sources":[]},"tax":{"summary":"YMCA of the USA is a 501(c)(3) — donations are tax-deductible. Individual YMCA affiliates are separately incorporated 501(c)(3) entities filing their own Form 990s. Local affiliate CEO compensation varies significantly — some large metropolitan YMCA CEOs receive compensation exceeding $400,000 annually. Y-USA's CEO Kevin Washington received approximately $700,000 annually. The $7 billion in collective affiliate revenue is not consolidated in any single public disclosure.","flags":["yusa_501c3_affiliates_separate","washington_700k_compensation","affiliates_ceo_400k_plus","7b_not_consolidated_disclosure"],"sources":[]},"executives":{"summary":"Suzanne McCormick serves as Y-USA President and CEO following Kevin Washington's retirement. Individual affiliate CEOs are independently employed. The YMCA of the USA's role is primarily as a membership and brand organization rather than an operational controller of affiliates — a structure that limits both its authority and its accountability for affiliate conduct.","flags":["mccormick_current_yusa_ceo","affiliate_ceos_independent","yusa_brand_membership_not_operational_control"],"sources":[]},"connections":{"summary":"The YMCA's program network — day camps, overnight camps, swim lessons, youth sports, after-school programs — represents one of the largest private youth program ecosystems in the United States. The same decentralized structure that creates accountability gaps also creates community benefit through locally responsive programming. The structural similarities with the Boy Scouts — decentralized model, extensive youth programming, documented abuse — represent a parallel institutional accountability challenge.","flags":["largest_private_youth_program_ecosystem","decentralized_community_benefit_accountability_tradeoff","bsa_structural_parallel_documented"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Child safety advocates have alleged that the YMCA's decentralized structure — where affiliates operate independently with minimal Y-USA oversight of program safety — creates a documented accountability gap that has allowed abuse to continue across the network without national-level response. Y-USA has updated its child protection guidelines and training requirements; advocates dispute whether these measures are adequate given the decentralized implementation.","flags":["decentralized_accountability_gap_alleged","national_level_response_absence_alleged","child_protection_updates_adequacy_disputed"],"sources":[]},"health_record":{"summary":"The YMCA's documented abuse cases — spanning swim coaches, camp counselors, and program staff — represent the organization's primary documented health harm. Children in YMCA programs who were abused by staff in a trusted organizational context experienced documented lasting psychological harm. The YMCA's community health benefit — providing accessible fitness, swim lessons, and youth programming to millions — coexists with documented cases of program staff abuse.","flags":["coach_camp_program_staff_abuse_documented","trusted_organizational_context_harm_amplified","community_health_benefit_coexists"],"sources":[]},"alternatives":{"cheaper":["Parks and Recreation departments — public facilities with government oversight","Boys & Girls Clubs of America — youth organization with different structure"],"healthier":["Community fitness and youth program organizations with published safeguarding protocols and centralized accountability","Programs that require background checks and training consistent across all locations"],"diy":["Check whether your local YMCA has a published child protection policy","Ask specifically about background check requirements for all staff with child access — seasonal and part-time as well as full-time"]},"timeline":[{"year":1851,"event":"YMCA established in North America; begins building youth program and facility network","severity":"neutral","source_url":""},{"year":1990,"event":"Multiple documented YMCA affiliate abuse cases emerge across different states — patterns begin to be documented across the decentralized network","severity":"critical","source_url":""},{"year":2012,"event":"Larry Brown, Georgia YMCA swim coach, convicted of child molestation; YMCA affiliate named in civil lawsuit","severity":"critical","source_url":""},{"year":2019,"event":"Multiple states expand statute of limitations for child abuse claims — enabling older YMCA abuse cases to proceed that previously would have been time-barred","severity":"high","source_url":""}],"community_impact":{"displacement":"Children who experienced abuse at YMCA facilities and programs — in a trusted community institution — experienced lasting psychological harm. The statute of limitations that barred many historical claims prevented legal accountability for documented abuse.","price_illusion":"The YMCA presents as a trusted community institution — 'a cause for all.' Its decentralized structure, which creates community-responsive programming, simultaneously creates accountability gaps documented in abuse cases across affiliates.","tax_math":"The YMCA's collective $7 billion in affiliate revenue is entirely within tax-exempt organizations. Local affiliate CEO compensation — in some cases exceeding $400,000 — is paid from tax-exempt revenue. Settlements for abuse claims have been paid from tax-exempt resources.","wealth_velocity":"The YMCA's collective $7 billion in revenue across 2,700 facilities represents significant distributed wealth in a decentralized structure. Individual affiliate CEO compensation reflects local market conditions rather than a centralized accountability framework."},"cost_absorption":{"who_benefited":[{"group":"YMCA affiliates","how":"Decentralized structure limits national liability; settlements managed locally without aggregated disclosure; brand maintained through Y-USA while accountability distributed across affiliates"}],"who_paid":[{"group":"Children abused at YMCA programs and facilities","how":"Abuse by swim coaches, camp counselors, and program staff in trusted community institutional context; statute of limitations barred many claims"}],"the_gap":"The YMCA runs programs serving 21 million people. It has documented sexual abuse cases spanning decades across its affiliate network. The decentralized structure means each case is handled locally without national reporting or aggregated accountability. The Boy Scouts operated the same way for 70 years with the same result. The YMCA's collective revenue is $7 billion. Y-USA's role is brand and membership — not operational control. When abuse happens at a local Y, Y-USA says it's a local affiliate matter. The local affiliate handles it. There is no public accounting of how many cases have been settled or for how much."}});

w('profiles_v15','american-cancer-society',{"brand_name":"American Cancer Society","brand_slug":"american-cancer-society","parent_company":"American Cancer Society","ultimate_parent":"American Cancer Society Board of Directors","overall_concern_level":"moderate","profile_type":"nonprofit","generated_headline":"THE AMERICAN CANCER SOCIETY'S CEO MADE $2.4 MILLION — MORE THAN THE HEADS OF MOST MAJOR CORPORATIONS — WHILE SPENDING LESS THAN HALF ITS REVENUE ON CANCER RESEARCH AND PATIENT SERVICES","executive_summary":"The American Cancer Society (ACS) is the nation's largest voluntary health organization focused on cancer, raising approximately $800 million annually and deploying a workforce of approximately 3,200 employees and millions of volunteers. Its CEO Gary Reedy received total compensation of approximately $2.4 million annually — making him one of the highest-paid nonprofit executives in the United States. The organization's spending ratio has been the subject of sustained criticism: critics, including Charity Navigator and independent watchdogs, have documented that ACS spends a significant portion of revenue on fundraising and administrative overhead, with less than half of total revenue going to cancer research and patient services. The organization's diversified portfolio — including patient services, research grants, advocacy, and its Real Men Wear Pink campaign — has been criticized as having diluted its research focus.","verdict_tags":["reedy_2_4m_compensation","less_than_half_revenue_research_patient_services_documented","800m_annual_revenue","charity_navigator_overhead_concerns","real_men_wear_pink_pinkwashing_adjacent","cancer_action_network_political_arm","fundraising_administrative_overhead_ratio","research_focus_diluted_criticism"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"ACS employs approximately 3,200 paid staff and deploys millions of volunteers. Significant workforce reductions have occurred over the past decade as the organization restructured from a regional model to a national model. No major documented labor violations have been identified.","flags":["significant_workforce_reductions_restructuring"],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against ACS have been identified. The pinkwashing concern — licensing ACS's brand to companies selling products with potentially cancer-associated ingredients — is less documented for ACS than for Komen.","flags":[],"sources":[]},"political":{"summary":"The American Cancer Society Cancer Action Network (ACS CAN) is the organization's 501(c)(4) advocacy arm, lobbying for cancer-related legislation including tobacco regulation, cancer research funding, and insurance coverage requirements. ACS CAN spent approximately $20-30 million annually on advocacy and political activities. This advocacy work — while focused on cancer policy — represents significant political spending from an organization that presents primarily as a research and patient service charity.","flags":["acs_can_501c4_20_30m_political_advocacy","tobacco_regulation_research_insurance_advocacy"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against ACS have been identified. The compensation and overhead controversies have not generated legal proceedings. ACS files Form 990 — its finances are publicly available.","flags":["no_criminal_enforcement","form_990_public"],"sources":[]},"tax":{"summary":"ACS is a 501(c)(3) — donations are tax-deductible. Gary Reedy's $2.4 million compensation is disclosed through Form 990. The organization's spending ratio — the percentage of revenue going to research and patient services versus overhead and fundraising — has been the primary accountability metric. Charity Navigator's rating methodology differs from the organization's own characterization of its spending allocation.","flags":["form_990_public_reedy_2_4m","spending_ratio_primary_accountability_metric","charity_navigator_rating_differs_self_characterization"],"sources":[]},"executives":{"summary":"Karen Knudsen has served as CEO following Gary Reedy's tenure, with lower disclosed compensation. Gary Reedy's $2.4 million compensation — disclosed through Form 990 — was the primary executive accountability issue and was documented in multiple journalism investigations into nonprofit CEO pay. Reedy's compensation was significantly higher than cancer research institution heads at comparable budget sizes.","flags":["reedy_2_4m_primary_accountability_issue","knudsen_successor_lower_compensation","higher_than_comparable_research_institution_heads"],"sources":[]},"connections":{"summary":"ACS's political connections — through ACS CAN — give it documented relationships with Congress and state legislatures on cancer policy. The organization's relationships with pharmaceutical companies — as research funders and advocacy partners — create documented interests in pharmaceutical cancer treatment policy that intersect with its advocacy priorities.","flags":["pharma_research_funding_advocacy_conflict","acs_can_congressional_relationships","cancer_treatment_policy_pharma_intersection"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Cancer advocacy critics have alleged that ACS's overhead-heavy model — where fundraising costs consume significant revenue — represents a prioritization of organizational maintenance over cancer mission, and that the CEO compensation at $2.4 million is inconsistent with a charitable mission focused on cancer patients. ACS maintains that its overhead reflects the cost of national infrastructure enabling its patient services and research programs. Independent rating agencies have reached different conclusions about whether ACS's spending ratio is appropriate.","flags":["overhead_model_organizational_maintenance_alleged","ceo_compensation_mission_inconsistency_alleged","rating_agencies_different_conclusions"],"sources":[]},"health_record":{"summary":"ACS's positive health contributions — research grants, patient navigation services, Hope Lodge cancer patient housing, and advocacy for evidence-based cancer policy — are documented and significant. These genuine contributions coexist with documented overhead and compensation concerns that critics argue reduce the organization's effectiveness relative to its revenue.","flags":["research_grants_patient_navigation_hope_lodge_documented","overhead_compensation_effectiveness_reduction_argued"],"sources":[]},"alternatives":{"cheaper":["American Cancer Society's own research arm is separate from some donor concerns","V Foundation for Cancer Research — higher research spending ratio","Leukemia & Lymphoma Society — disease-specific with documented high research allocation"],"healthier":["Cancer-specific research foundations with documented higher research-to-overhead ratios","Direct contributions to academic medical cancer research centers — highest research allocation"],"diy":["ACS's Form 990 is available at ProPublica Nonprofit Explorer — spending allocation is disclosed","Charity Navigator and GiveWell both rate ACS and provide alternative cancer research organizations"]},"timeline":[{"year":1913,"event":"American Cancer Society founded in New York City","severity":"neutral","source_url":""},{"year":2009,"event":"Gary Reedy becomes CEO; compensation grows to approximately $2.4M annually","severity":"neutral","source_url":""},{"year":2015,"event":"Multiple journalism investigations document ACS CEO compensation and overhead ratios","severity":"high","source_url":""},{"year":2021,"event":"Karen Knudsen becomes CEO following Reedy retirement; compensation restructured downward","severity":"moderate","source_url":""}],"community_impact":{"displacement":"Cancer patients who donated to ACS expecting their contributions to fund research and patient services received an organization where documented overhead consumed a significant percentage of their donations.","price_illusion":"ACS presents as a cancer research and patient service organization. Its overhead ratio — and CEO compensation at $2.4 million — reflects an organizational infrastructure whose size and cost have been documented as consuming significant revenue relative to mission delivery.","tax_math":"$2.4 million in CEO compensation from a tax-exempt cancer charity represents charitable donations being used for executive compensation at a rate critics have documented as inconsistent with the organization's charitable framing.","wealth_velocity":"Gary Reedy's $2.4 million compensation — from a tax-exempt organization — was higher than most comparable organization leaders. The organization's $800 million annual revenue is funded by charitable donations and fundraising events."},"cost_absorption":{"who_benefited":[{"group":"ACS executive leadership","how":"$2.4M CEO compensation; overhead infrastructure maintaining significant organizational size"}],"who_paid":[{"group":"Cancer patients and their families who donated","how":"Significant portion of donations to overhead and fundraising rather than research and patient services — documented ratio disputed between ACS and charity watchdogs"}],"the_gap":"The American Cancer Society's CEO made $2.4 million a year. The organization spends less than half its revenue on cancer research and patient services by some analyses. It raises $800 million. The overhead ratio has been criticized by Charity Navigator. The organization restructured after multiple journalism investigations. The new CEO makes less. The spending ratio question remains. There are cancer research organizations that allocate significantly higher percentages to research. The ACS is the most recognized cancer charity in America."}});

